snippets.java:
// Manual frequency count
Map<Character, Integer> freq = new HashMap<>();
for (char ch : str.toCharArray()) {
    freq.merge(ch, 1, Integer::sum);
}

// Or with getOrDefault
for (char ch : str.toCharArray()) {
    freq.put(ch, freq.getOrDefault(ch, 0) + 1);
}

